import boto3
import json

class SQSPublisher:
    def __init__(self, queue_url):
        self.sqs = boto3.client('sqs')
        self.queue_url = queue_url
        
    def publish_message(self, user_data):
        self.sqs.send_message(
            QueueUrl=self.queue_url,
            MessageBody=json.dumps(user_data),
            MessageAttributes={
                'pii_data': {
                    'StringValue': 'true',
                    'DataType': 'String'
                }
            }
        )

# Example usage
